#!/bin/sh
set -eu

perl -0pi -e 's#static int mix_music_in_sdl_device = 0;\n#static int mix_music_in_sdl_device = 0;\nstatic int shock_audio_rate = 32000;\nstatic int shock_audio_chunk = 4096;\nstatic int ShockEnvInt(const char *name, int fallback, int minv, int maxv) {\n    const char *value = SDL_getenv(name);\n    int parsed;\n    if (value == NULL || value[0] == 0)\n        return fallback;\n    parsed = SDL_atoi(value);\n    if (parsed < minv || parsed > maxv)\n        return fallback;\n    return parsed;\n}\n#' src/MacSrc/SDLSound.c

perl -0pi -e 's@static Mix_Chunk \*samples_by_channel\[SND_MAX_SAMPLES\];@static Mix_Chunk *samples_by_channel[SND_MAX_SAMPLES];\n\ntypedef struct CachedSample {\n    int snd_ref;\n    int len;\n    Mix_Chunk *chunk;\n} CachedSample;\n\n#define SAMPLE_CACHE_SIZE 128\nstatic CachedSample sample_cache[SAMPLE_CACHE_SIZE];\nstatic int sample_cache_next = 0;\n\nstatic Mix_Chunk *ShockGetCachedSample(int snd_ref, int len, uchar *smp) {\n    int i;\n\n    for (i = 0; i < SAMPLE_CACHE_SIZE; ++i) {\n        if (sample_cache[i].chunk != NULL && sample_cache[i].snd_ref == snd_ref && sample_cache[i].len == len)\n            return sample_cache[i].chunk;\n    }\n\n    Mix_Chunk *chunk = Mix_LoadWAV_RW(SDL_RWFromConstMem(smp, len), 1);\n    if (chunk == NULL)\n        return NULL;\n\n    if (sample_cache[sample_cache_next].chunk != NULL)\n        Mix_FreeChunk(sample_cache[sample_cache_next].chunk);\n\n    sample_cache[sample_cache_next].snd_ref = snd_ref;\n    sample_cache[sample_cache_next].len = len;\n    sample_cache[sample_cache_next].chunk = chunk;\n    sample_cache_next = (sample_cache_next + 1) % SAMPLE_CACHE_SIZE;\n\n    return chunk;\n}\n@' src/MacSrc/SDLSound.c

perl -0pi -e 's#int snd_using_primary_audio_mix\(void\) \{#static void ShockPostMix(void *userdata, unsigned char *stream, int len) {\n    SDL_AudioStream *as = userdata != NULL ? *(SDL_AudioStream **)userdata : NULL;\n\n    if (as != NULL && SDL_AudioStreamAvailable(as) > 0) {\n        Uint8 *mix_stream = SDL_malloc((size_t)len);\n        if (mix_stream != NULL) {\n            int got;\n            SDL_memset(mix_stream, 0, (size_t)len);\n            got = SDL_AudioStreamGet(as, mix_stream, len);\n            if (got > 0)\n                SDL_MixAudioFormat(stream, mix_stream, AUDIO_S16SYS, (Uint32)got, SDL_MIX_MAXVOLUME);\n            SDL_free(mix_stream);\n        }\n    }\n}\n\nint snd_using_primary_audio_mix(void) {#' src/MacSrc/SDLSound.c

perl -0pi -e 's#int snd_start_digital\(void\) \{#int snd_output_rate(void) {\n    return shock_audio_rate;\n}\n\nint snd_start_digital(void) {#' src/MacSrc/SDLSound.c

perl -0pi -e 's#    SDL_AudioSpec spec, obtained;\n    spec.freq = 48000;\n    spec.format = AUDIO_S16SYS;\n    spec.channels = 2;\n    spec.samples = 2048;\n    spec.callback = ShockAudioCallback;\n    spec.userdata = \(void \*\)&cutscene_audiostream;\n\n    extern SDL_AudioDeviceID device;\n    device = SDL_OpenAudioDevice\(NULL, 0, &spec, &obtained, 0\);\n\n    if \(device == 0\) \{\n        ERROR\("Could not open SDL audio: %s", SDL_GetError\(\)\);\n    \} else \{\n        INFO\("Opened Music Stream, deviceID %d, freq %d, size %d, format %d, channels %d, samples %d", device,\n             obtained.freq, obtained.size, obtained.format, obtained.channels, obtained.samples\);\n    \}\n#    extern SDL_AudioDeviceID device;\n    int mix_freq = 0, mix_channels = 0;\n    Uint16 mix_format = 0;\n\n    device = 0;\n#' src/MacSrc/SDLSound.c

perl -0pi -e 's#    if \(Mix_OpenAudio\(48000, AUDIO_S16SYS, 2, 2048\) < 0\) \{\n        ERROR\("%s: Couldn.t open audio device", __FUNCTION__\);\n        INFO\("%s: Routing MIDI through the primary SDL audio device", __FUNCTION__\);\n        mix_music_in_sdl_device = 1;\n        SDL_PauseAudioDevice\(device, 0\);\n    \} else \{\n        Mix_HookMusic\(MusicCallback, \(void \*\)&MusicDev\);\n        Mix_VolumeMusic\(MIX_MAX_VOLUME\); // use max volume for music stream\n    \}#    shock_audio_rate = ShockEnvInt("SHOCK_AUDIO_RATE", 32000, 22050, 96000);\n    shock_audio_chunk = ShockEnvInt("SHOCK_AUDIO_CHUNK", 4096, 512, 16384);\n    INFO("Requested SDL_mixer audio, freq %d, chunk %d", shock_audio_rate, shock_audio_chunk);\n\n    if (Mix_OpenAudio(shock_audio_rate, AUDIO_S16SYS, 2, shock_audio_chunk) < 0) {\n        ERROR("%s: Couldn.t open SDL_mixer audio device: %s", __FUNCTION__, Mix_GetError());\n        return ERR_NOEFFECT;\n    } else {\n        Mix_QuerySpec(&mix_freq, &mix_format, &mix_channels);\n        if (mix_freq > 0)\n            shock_audio_rate = mix_freq;\n        INFO("Opened SDL_mixer audio, freq %d, format %d, channels %d, chunk %d", mix_freq, mix_format, mix_channels, shock_audio_chunk);\n        Mix_SetPostMix(ShockPostMix, (void *)&cutscene_audiostream);\n        Mix_HookMusic(MusicCallback, (void *)&MusicDev);\n        Mix_VolumeMusic(MIX_MAX_VOLUME); // use max volume for music stream\n    }#' src/MacSrc/SDLSound.c

perl -0pi -e 's#int snd_sample_play\(int snd_ref, int len, uchar \*smp, struct snd_digi_parms \*dprm\) \{\n\n    // Play one of the VOC format sounds\n\n    Mix_Chunk \*sample = Mix_LoadWAV_RW\(SDL_RWFromConstMem\(smp, len\), 1\);\n    if \(sample == NULL\) \{\n        DEBUG\("%s: Failed to load sample", __FUNCTION__\);\n        return ERR_NOEFFECT;\n    \}\n\n    int loops = dprm->loops > 0 \? dprm->loops - 1 : -1;\n    int channel = Mix_PlayChannel\(-1, sample, loops\);\n    if \(channel < 0\) \{\n        DEBUG\("%s: Failed to play sample", __FUNCTION__\);\n        Mix_FreeChunk\(sample\);\n        return ERR_NOEFFECT;\n    \}\n\n    if \(samples_by_channel\[channel\]\)\n        Mix_FreeChunk\(samples_by_channel\[channel\]\);\n\n    samples_by_channel\[channel\] = sample;\n    digi_parms_by_channel\[channel\] = \*dprm;\n    snd_sample_reload_parms\(&digi_parms_by_channel\[channel\]\);\n\n    return channel;\n\}#int snd_sample_preload(int snd_ref, int len, uchar *smp) {\n    return ShockGetCachedSample(snd_ref, len, smp) != NULL ? OK : ERR_NOEFFECT;\n}\n\nint snd_sample_play(int snd_ref, int len, uchar *smp, struct snd_digi_parms *dprm) {\n\n    // Play one of the VOC format sounds. Cache decoded chunks by resource id\n    // so repeated loud effects do not re-run SDL_mixer conversion mid-frame.\n\n    Mix_Chunk *sample = ShockGetCachedSample(snd_ref, len, smp);\n    if (sample == NULL) {\n        DEBUG("%s: Failed to load sample", __FUNCTION__);\n        return ERR_NOEFFECT;\n    }\n\n    int loops = dprm->loops > 0 ? dprm->loops - 1 : -1;\n    int channel = Mix_PlayChannel(-1, sample, loops);\n    if (channel < 0) {\n        DEBUG("%s: Failed to play sample", __FUNCTION__);\n        return ERR_NOEFFECT;\n    }\n\n    samples_by_channel[channel] = sample;\n    digi_parms_by_channel[channel] = *dprm;\n    snd_sample_reload_parms(&digi_parms_by_channel[channel]);\n\n    return channel;\n}#' src/MacSrc/SDLSound.c

perl -0pi -e 's#void snd_end_sample\(int hnd_id\) \{\n    Mix_HaltChannel\(hnd_id\);\n    if \(samples_by_channel\[hnd_id\]\) \{\n        Mix_FreeChunk\(samples_by_channel\[hnd_id\]\);\n        samples_by_channel\[hnd_id\] = NULL;\n    \}\n\}#void snd_end_sample(int hnd_id) {\n    Mix_HaltChannel(hnd_id);\n    samples_by_channel[hnd_id] = NULL;\n}#' src/MacSrc/SDLSound.c

perl -0pi -e 's#static SDL_mutex \*MyMutex;\n#static SDL_mutex *MyMutex;\n\nextern int snd_output_rate(void);\n\n#define MUSIC_RENDER_FRAMES 512\n#define MUSIC_FIFO_TARGET_BYTES 32768\n\nstatic SDL_AudioStream *MusicFifo;\nstatic SDL_mutex *MusicFifoMutex;\nstatic SDL_Thread *MusicRenderThread;\nstatic SDL_atomic_t MusicRenderRunning;\n\nstatic int AnyMusicThreadPlaying(void) {\n    for (int i = 0; i < NUM_THREADS; ++i) {\n        if (SDL_AtomicGet(&ThreadPlaying[i]))\n            return 1;\n    }\n    return 0;\n}\n\nstatic int MusicRenderMain(void *unused) {\n    short buffer[MUSIC_RENDER_FRAMES * 2];\n\n    SDL_SetThreadPriority(SDL_THREAD_PRIORITY_HIGH);\n\n    while (SDL_AtomicGet(&MusicRenderRunning)) {\n        int available = 0;\n\n        if (!AnyMusicThreadPlaying()) {\n            if (MusicFifoMutex != NULL) {\n                SDL_LockMutex(MusicFifoMutex);\n                if (MusicFifo != NULL)\n                    SDL_AudioStreamClear(MusicFifo);\n                SDL_UnlockMutex(MusicFifoMutex);\n            }\n            SDL_Delay(5);\n            continue;\n        }\n\n        if (MusicFifoMutex != NULL) {\n            SDL_LockMutex(MusicFifoMutex);\n            if (MusicFifo != NULL)\n                available = SDL_AudioStreamAvailable(MusicFifo);\n            SDL_UnlockMutex(MusicFifoMutex);\n        }\n\n        if (available >= MUSIC_FIFO_TARGET_BYTES) {\n            SDL_Delay(2);\n            continue;\n        }\n\n        SDL_memset(buffer, 0, sizeof(buffer));\n\n        SDL_LockMutex(MyMutex);\n        if (MusicDev != NULL && MusicDev->isOpen)\n            MusicDev->generate(MusicDev, buffer, MUSIC_RENDER_FRAMES);\n        SDL_UnlockMutex(MyMutex);\n\n        if (MusicFifoMutex != NULL) {\n            SDL_LockMutex(MusicFifoMutex);\n            if (MusicFifo != NULL)\n                SDL_AudioStreamPut(MusicFifo, buffer, sizeof(buffer));\n            SDL_UnlockMutex(MusicFifoMutex);\n        }\n    }\n\n    return 0;\n}\n\nstatic void StopMusicRenderThread(void) {\n    if (MusicRenderThread != NULL) {\n        SDL_AtomicSet(&MusicRenderRunning, 0);\n        SDL_WaitThread(MusicRenderThread, NULL);\n        MusicRenderThread = NULL;\n    }\n\n    if (MusicFifoMutex != NULL) {\n        SDL_LockMutex(MusicFifoMutex);\n        if (MusicFifo != NULL) {\n            SDL_FreeAudioStream(MusicFifo);\n            MusicFifo = NULL;\n        }\n        SDL_UnlockMutex(MusicFifoMutex);\n    }\n}\n\nstatic void StartMusicRenderThread(void) {\n    int rate;\n\n    if (MusicRenderThread != NULL)\n        return;\n\n    rate = snd_output_rate();\n    if (MusicFifoMutex == NULL)\n        MusicFifoMutex = SDL_CreateMutex();\n\n    if (MusicFifoMutex == NULL)\n        return;\n\n    SDL_LockMutex(MusicFifoMutex);\n    MusicFifo = SDL_NewAudioStream(AUDIO_S16SYS, 2, rate, AUDIO_S16SYS, 2, rate);\n    SDL_UnlockMutex(MusicFifoMutex);\n\n    if (MusicFifo == NULL)\n        return;\n\n    SDL_AtomicSet(&MusicRenderRunning, 1);\n    MusicRenderThread = SDL_CreateThread(MusicRenderMain, "ShockMidi", NULL);\n    if (MusicRenderThread == NULL) {\n        SDL_AtomicSet(&MusicRenderRunning, 0);\n        StopMusicRenderThread();\n    }\n}\n#' src/MacSrc/Xmi.c

perl -0pi -e 's#void MusicCallback\(void \*userdata, Uint8 \*stream, int len\) \{\n    MusicDevice \*dev;\n\n    SDL_LockMutex\(MyMutex\);\n    dev = \*\(MusicDevice \*\*\)userdata;\n    if \(!dev \|\| !dev->isOpen\) \{\n        SDL_UnlockMutex\(MyMutex\);\n        return;\n    \}\n\n    SDL_memset\(stream, 0, \(size_t\)len\); // in case we don.t get anything\n    dev->generate\(dev, \(short \*\)\(\(void \*\)stream\), len / \(int\)\(2 \* sizeof\(short\)\)\);\n    SDL_UnlockMutex\(MyMutex\);\n\}#void MusicCallback(void *userdata, Uint8 *stream, int len) {\n    int got = 0;\n\n    (void)userdata;\n    SDL_memset(stream, 0, (size_t)len);\n\n    if (MusicFifoMutex == NULL)\n        return;\n\n    SDL_LockMutex(MusicFifoMutex);\n    if (MusicFifo != NULL)\n        got = SDL_AudioStreamGet(MusicFifo, stream, len);\n    SDL_UnlockMutex(MusicFifoMutex);\n\n    if (got > 0 && got < len)\n        SDL_memset(stream + got, 0, (size_t)(len - got));\n}#' src/MacSrc/Xmi.c

perl -0pi -e 's#int musicrate = 48000;#int musicrate = snd_output_rate();#' src/MacSrc/Xmi.c
perl -0pi -e 's#    MusicDev = musicdev;\n    SDL_UnlockMutex\(MyMutex\);#    MusicDev = musicdev;\n    StartMusicRenderThread();\n    SDL_UnlockMutex(MyMutex);#' src/MacSrc/Xmi.c
perl -0pi -e 's#        SDL_LockMutex\(MyMutex\);\n        MusicDev->destroy\(MusicDev\);#        StopMusicRenderThread();\n\n        SDL_LockMutex(MyMutex);\n        MusicDev->destroy(MusicDev);#' src/MacSrc/Xmi.c
perl -0pi -e 's#    InitDecXMI\(\);\n\n    MyMutex = SDL_CreateMutex\(\);#    MyMutex = SDL_CreateMutex();\n\n    InitDecXMI();#' src/MacSrc/Xmi.c
perl -0pi -e 's#    INFO\("Closing MIDI driver due to shutdown"\);#    StopMusicRenderThread();\n\n    INFO("Closing MIDI driver due to shutdown");#' src/MacSrc/Xmi.c

perl -0pi -e 's#int   snd_sample_play\(int snd_ref, int len, uchar \*smp, struct snd_digi_parms \*dprm\);#int   snd_sample_preload(int snd_ref, int len, uchar *smp);\nint   snd_sample_play(int snd_ref, int len, uchar *smp, struct snd_digi_parms *dprm);#' src/Libraries/SND/Source/lgsndx.h

perl -0pi -e 's#    fclose\(fp\);\n    // clear_digi_fx\(\);#    fclose(fp);\n\n    // Decode every gameplay VOC while the startup screen is still visible.\n    // DIGIFX.RES contains 114 effects, which fit in the fixed 128-entry cache.\n    for (int i = 0; i < NUM_DIGI_FX; ++i) {\n        Id vocRes = SFX_BASE + i;\n        uchar *addr = (uchar *)ResLock(vocRes);\n        int len = ResSize(vocRes);\n\n        if (addr != NULL && len > 0)\n            snd_sample_preload(vocRes, len, addr);\n        if (addr != NULL)\n            ResUnlock(vocRes);\n    }\n    // clear_digi_fx();#' src/GameSrc/digifx.c

for file in src/GameSrc/cutsloop.c src/GameSrc/audiolog.c; do
    perl -0pi -e 's#extern int snd_using_primary_audio_mix\(void\);\n#extern int snd_using_primary_audio_mix(void);\nextern int snd_output_rate(void);\n#' "$file"
    perl -0pi -e 's#SDL_PauseAudioDevice\(device, ([01])\);#if (device != 0) SDL_PauseAudioDevice(device, $1);#g' "$file"
    perl -0pi -e 's#fix_int\((a?movie|palog)->a.sampleRate\), AUDIO_S16SYS, 2, 48000\)#fix_int($1->a.sampleRate), AUDIO_S16SYS, 2, snd_output_rate())#' "$file"
done

perl -0pi -e 's#typedef struct AdlMidiDevice\n\{\n    MusicDevice dev;\n    struct ADL_MIDIPlayer \*adl;\n\} AdlMidiDevice;#typedef struct AdlMidiDevice\n{\n    MusicDevice dev;\n    struct ADL_MIDIPlayer *adl;\n    int modeInitialized;\n    MusicMode currentMode;\n} AdlMidiDevice;#' src/MusicSrc/MusicDevice.c

perl -0pi -e 's#    //Use sound bank 45 for res/sound/sblaster, 0 for res/sound/genmidi\n    adl_setBank\(adev->adl, \(mode == Music_SoundBlaster\) \? 45 : 0\);#    if (adev->modeInitialized && adev->currentMode == mode)\n        return;\n\n    //Use sound bank 45 for res/sound/sblaster, 0 for res/sound/genmidi\n    adl_setBank(adev->adl, (mode == Music_SoundBlaster) ? 45 : 0);\n\n    adev->modeInitialized = 1;\n    adev->currentMode = mode;\n    adev->dev.musicType = (mode == Music_SoundBlaster) ? MUSICTYPE_SBLASTER : MUSICTYPE_GENMIDI;#' src/MusicSrc/MusicDevice.c

perl -0pi -e 's#    adev->dev.musicType = MUSICTYPE_SBLASTER;\n    return &adev->dev;#    adev->dev.musicType = MUSICTYPE_SBLASTER;\n    adev->modeInitialized = 0;\n    adev->currentMode = Music_SoundBlaster;\n    return &adev->dev;#' src/MusicSrc/MusicDevice.c

grep -R "ADLMIDI_EMU_DOSBOX\|modeInitialized\|ShockGetCachedSample\|Requested SDL_mixer audio\|Opened SDL_mixer audio\|Mix_SetPostMix\|snd_output_rate\|MusicRenderMain\|StartMusicRenderThread\|SDL_PauseAudioDevice" -n src/MusicSrc/MusicDevice.c src/MacSrc/SDLSound.c src/MacSrc/Xmi.c src/GameSrc/cutsloop.c src/GameSrc/audiolog.c
